1	// WORKSTATE 상태 전이의 유일한 writer.
2	// prepare: 전이 계획(envelope+candidate)을 outputs/state-transition/에 기록한다.
3	// apply: reconciliation-먼저, 멱등 결속, rollback, FATAL 분류 포함 전이를 실행한다.
4	using System.Globalization;
5	using System.Security.Cryptography;
6	using System.Text;
7	using System.Text.Encodings.Web;
8	using System.Text.Json;
9	using System.Text.Json.Nodes;
10	using System.Text.RegularExpressions;
11	
12	internal static class StateApplierCli
13	{
14	    private static readonly JsonSerializerOptions WriteOptions = new()
15	    {
16	        WriteIndented = true,
17	        Encoder = JavaScriptEncoder.UnsafeRelaxedJsonEscaping,
18	    };
19	
20	    private static readonly HashSet<string> ValidStatuses = new(StringComparer.OrdinalIgnoreCase)
21	    {
22	        "waiting", "in_progress", "verifying", "completed", "blocked",
23	    };
24	
25	    // 허용 전이 화이트리스트 — 이 표 밖의 전이는 전부 거부(completed는 terminal).
26	    private static readonly Dictionary<string, HashSet<string>> AllowedTransitions = new(StringComparer.OrdinalIgnoreCase)
27	    {
28	        ["waiting"] = new(StringComparer.OrdinalIgnoreCase) { "in_progress", "blocked" },
29	        ["in_progress"] = new(StringComparer.OrdinalIgnoreCase) { "verifying", "blocked", "waiting" },
30	        ["verifying"] = new(StringComparer.OrdinalIgnoreCase) { "completed", "in_progress", "blocked" },
31	        ["blocked"] = new(StringComparer.OrdinalIgnoreCase) { "waiting", "in_progress", "verifying" },
32	        ["completed"] = new(StringComparer.OrdinalIgnoreCase) { },
33	    };
34	
35	    // nextActions 필수 status 목록(completed 제외).
36	    private static readonly HashSet<string> NextActionsRequired = new(StringComparer.OrdinalIgnoreCase)
37	    {
38	        "waiting", "in_progress", "verifying", "blocked",
39	    };
40	
41	    // 허용 transitionKind 목록 — 이 밖은 unknown-transition-kind로 fail-closed.
42	    private static readonly HashSet<string> ValidTransitionKinds = new(StringComparer.OrdinalIgnoreCase)
43	    {
44	        "NORMAL", "PHASE_CHANGE", "RECOVERY", "REPLAY",
45	    };
46	
47	    // high-risk transitionKind — receipt ledger 부재로 이번 WP에서 fail-closed.
48	    private static readonly HashSet<string> HighRiskKinds = new(StringComparer.OrdinalIgnoreCase)
49	    {
50	        "PHASE_CHANGE", "RECOVERY", "REPLAY",
51	    };
52	
53	    // 파싱된 envelope 데이터 레코드.
54	    private record EnvelopeData(
55	        int SchemaVersion,
56	        string TransitionKind,
57	        string TransitionId,
58	        string ExpectedPreStateSha256,
59	        string RequestPath,
60	        string RequestSha256,
61	        string EffectiveAt,
62	        string ExpectedPostStateSha256,
63	        string? TransitionContractSha256,
64	        string CandidatePath);
65	
66	    // prepare 부속 명령 옵션.
67	    private record PrepareOptions(string TransitionId, string RequestPath, bool DryRun);
68	
69	    // apply 부속 명령 옵션.
70	    private record ApplyOptions(string EnvelopePath, string? VerdictPath, bool DryRun);
71	
72	    // 결정적 test seam — 같은 프로세스의 자기 시험 코드만 설정할 수 있다. production 진입점(CLI·환경변수·설정파일)에서 켤 수 없음.
73	    internal static Func<string?>? FailAfterWriteHook;
74	
75	    // 결정적 projection seam — 자기 시험 코드만 설정. 환경변수·CLI에서 켤 수 없음.
76	    internal static Func<int>? ProjectionOverride;
77	
78	    // 결정적 복원 실패 seam — rollback 내 복원 단계를 실패시킨다. 자기 시험 코드만 설정.
79	    internal static bool FailRestoreForTest;
80	
81	    // 삭제된 옵션과 그 이유 메시지 — 일반 unknown-option과 구분한 명시적 오류.
82	    private static readonly Dictionary<string, string> RemovedOptions = new(StringComparer.OrdinalIgnoreCase)
83	    {
84	        ["human-decision"] = "removed-option: --human-decision (06C-1-R1에서 삭제됨. PHASE_CHANGE/RECOVERY/REPLAY는 trusted-human-receipt-required로 fail-closed)",
85	        ["root"] = "removed-option: --root (06C-1-R1에서 삭제됨. 사본 시험은 process cwd를 바꿔서 하라)",
86	    };
87	
88	    // prepare 허용 키 — 이 밖의 키는 ValidateOptions에서 거부한다.
89	    private static readonly HashSet<string> PrepareKnownKeys = new(StringComparer.OrdinalIgnoreCase)
90	        { "transition-id", "request", "dry-run-flag" };
91	
92	    // apply 허용 키 — 이 밖의 키는 ValidateOptions에서 거부한다.
93	    private static readonly HashSet<string> ApplyKnownKeys = new(StringComparer.OrdinalIgnoreCase)
94	        { "envelope", "verdict", "dry-run-flag" };
95	
96	    // state-transition 진입점. prepare/apply/--self-test를 args[1]로 분기하고 그 외는 exit 2.
97	    internal static int Run(string[] args)
98	    {
99	        var sub = args.Length > 1 ? args[1] : "";
100	        if (string.Equals(sub, "prepare", StringComparison.OrdinalIgnoreCase))
101	            return RunPrepare(args);
102	        if (string.Equals(sub, "apply", StringComparison.OrdinalIgnoreCase))
103	            return RunApply(args);
104	        if (string.Equals(sub, "--self-test", StringComparison.OrdinalIgnoreCase))
105	            return RunSelfTest();
106	        Console.Error.WriteLine("{\"error\":\"state-transition usage: prepare --transition-id <id> --request <file> | apply --envelope <file> | --self-test\"}");
107	        return 2;
108	    }
109	
110	    // prepare: 옵션을 검증하고 root를 찾아 RunPrepareCore에 위임한다.
111	    private static int RunPrepare(string[] args)
112	    {
113	        var optErr = ValidateOptions(ParseFlagMap(args, 2), PrepareKnownKeys);
114	        if (optErr is not null) { Console.Error.WriteLine($"{{\"error\":\"{optErr}\"}}"); return 2; }
115	        var opts = ParsePrepareArgs(args);
116	        if (opts is null)
117	        {
118	            Console.Error.WriteLine("{\"error\":\"prepare에는 --transition-id, --request 가 필요합니다\"}");
119	            return 2;
120	        }
121	        try { return RunPrepareCore(GitTools.FindRepoRoot(), opts); }
122	        catch (Exception ex) { Console.Error.WriteLine($"{{\"error\":\"state-transition prepare 실패: {ex.Message}\"}}"); return 2; }
123	    }
124	
125	    // prepare 핵심 — root를 명시적으로 받아 자기 시험과 production 경로 공유.
126	    private static int RunPrepareCore(string root, PrepareOptions opts)
127	    {
128	        var workstatePath = Path.Combine(root, "docs", "handoff", "WORKSTATE.json");
129	        if (!File.Exists(workstatePath)) { WriteError("WORKSTATE.json not found"); return 2; }
130	
131	        var rawWorkstate = File.ReadAllText(workstatePath, new UTF8Encoding(false));
132	        var workstate = JsonNode.Parse(rawWorkstate)?.AsObject();
133	        if (workstate is null) { WriteError("WORKSTATE.json is not a valid JSON object"); return 2; }
134	
135	        if (!File.Exists(opts.RequestPath)) { WriteError($"request file not found: {opts.RequestPath}"); return 2; }
136	        var rawRequest = File.ReadAllText(opts.RequestPath, new UTF8Encoding(false));
137	        var request = JsonNode.Parse(rawRequest)?.AsObject();
138	        if (request is null) { WriteError("request JSON must be a JSON object"); return 2; }
139	
140	        // 해시 계산 + effectiveAt 발급 (NORMAL은 prepare가 현재 UTC를 발급, 외부 플래그 없음).
141	        var preStateSha256 = ComputeSha256(rawWorkstate);
142	        var requestSha256 = ComputeSha256(rawRequest);
143	        var effectiveAt = DateTime.UtcNow.ToString("o");
144	
145	        // 결정적 candidate 계산 — UtcNow 호출 없이 effectiveAt을 파라미터로 받는다.
146	        var candidate = BuildCandidate(workstate, request, opts.TransitionId, effectiveAt);
147	        var candidateBytes = Encoding.UTF8.GetBytes(candidate.ToJsonString(WriteOptions));
148	        var postStateSha256 = Convert.ToHexString(SHA256.HashData(candidateBytes)).ToLowerInvariant();
149	        var contractHash = ComputeContractHash(
150	            opts.TransitionId, "NORMAL", requestSha256, preStateSha256, postStateSha256, effectiveAt);
151	
152	        if (opts.DryRun)
153	        {
154	            Console.WriteLine(new JsonObject
155	            {
156	                ["ok"] = true, ["dryRun"] = true,
157	                ["transitionId"] = opts.TransitionId,
158	                ["preStateSha256"] = preStateSha256,
159	                ["expectedPostStateSha256"] = postStateSha256,
160	                ["transitionContractSha256"] = contractHash,
161	            }.ToJsonString(WriteOptions));
162	            return 0;
163	        }
164	
165	        return WritePrepareOutput(root, opts, preStateSha256, requestSha256, postStateSha256, contractHash, candidateBytes, effectiveAt);
166	    }
167	
168	    // envelope+candidate 파일을 outputs/state-transition/에 기록하고 결과를 출력한다.
169	    private static int WritePrepareOutput(
170	        string root, PrepareOptions opts, string preStateSha256, string requestSha256,
171	        string postStateSha256, string contractHash, byte[] candidateBytes, string effectiveAt)
172	    {
173	        var outDir = Path.Combine(root, "outputs", "state-transition");
174	        Directory.CreateDirectory(outDir);
175	        var safeTid = Regex.Replace(opts.TransitionId, @"[^\w\-]", "_");
176	
177	        // candidate 파일 기록 — evidence용. apply는 이 파일을 canonical write에 쓰지 않는다.
178	        var candidatePath = Path.Combine(outDir, $"{safeTid}.candidate.json");
179	        File.WriteAllBytes(candidatePath, candidateBytes);
180	
181	        var envelope = new JsonObject
182	        {
183	            ["schemaVersion"] = 1,
184	            ["transitionKind"] = "NORMAL",
185	            ["transitionId"] = opts.TransitionId,
186	            ["expectedPreStateSha256"] = preStateSha256,
187	            ["requestPath"] = opts.RequestPath,
188	            ["requestSha256"] = requestSha256,
189	            ["effectiveAt"] = effectiveAt,
190	            ["expectedPostStateSha256"] = postStateSha256,
191	            ["transitionContractSha256"] = contractHash,
192	            ["candidatePath"] = candidatePath,
193	        };
194	
195	        var envelopePath = Path.Combine(outDir, $"{safeTid}.envelope.json");
196	        File.WriteAllText(envelopePath, envelope.ToJsonString(WriteOptions), new UTF8Encoding(false));
197	
198	        Console.WriteLine(new JsonObject
199	        {
200	            ["ok"] = true,
201	            ["transitionId"] = opts.TransitionId,
202	            ["envelopePath"] = envelopePath,
203	            ["candidatePath"] = candidatePath,
204	            ["preStateSha256"] = preStateSha256,
205	            ["expectedPostStateSha256"] = postStateSha256,
206	            ["transitionContractSha256"] = contractHash,
207	        }.ToJsonString(WriteOptions));
208	        return 0;
209	    }
