211	    // apply: 옵션을 검증하고 ApplyEnvelopeCore에 위임한다.
212	    private static int RunApply(string[] args)
213	    {
214	        var optErr = ValidateOptions(ParseFlagMap(args, 2), ApplyKnownKeys);
215	        if (optErr is not null) { Console.Error.WriteLine($"{{\"error\":\"{optErr}\"}}"); return 2; }
216	        var opts = ParseApplyArgs(args);
217	        if (opts is null)
218	        {
219	            Console.Error.WriteLine("{\"error\":\"apply에는 --envelope 이 필요합니다\"}");
220	            return 2;
221	        }
222	
223	        var envelope = ReadEnvelope(opts.EnvelopePath);
224	        if (envelope is null) return 2;
225	
226	        var ctx = LoadWorkstateContextFromRoot(GitTools.FindRepoRoot());
227	        if (ctx is null) return 2;
228	        return ApplyEnvelopeCore(ctx.Value, envelope, opts.DryRun);
229	    }
230	
231	    // apply 핵심 — root를 명시적으로 받아 자기 시험과 production 경로 공유.
232	    private static int ApplyEnvelopeCore(
233	        (string root, string workstatePath, string logPath, byte[] rawWorkstateBytes, JsonObject workstate, string rawWorkstateStr) ctx,
234	        EnvelopeData envelope, bool dryRun)
235	    {
236	        // unknown transitionKind는 fail-closed — NORMAL/PHASE_CHANGE/RECOVERY/REPLAY 외 거부.
237	        if (!ValidTransitionKinds.Contains(envelope.TransitionKind))
238	            return Fail(1, envelope.TransitionId, "unknown-transition-kind",
239	                $"transitionKind='{envelope.TransitionKind}'은 알 수 없는 종류입니다 (허용: NORMAL, PHASE_CHANGE, RECOVERY, REPLAY)");
240	
241	        // high-risk transitionKind — receipt ledger 부재로 항상 fail-closed.
242	        if (HighRiskKinds.Contains(envelope.TransitionKind))
243	            return Fail(1, envelope.TransitionId, "trusted-human-receipt-required",
244	                $"transitionKind={envelope.TransitionKind}는 receipt ledger 부재로 이번 WP에서 fail-closed");
245	
246	        var (root, workstatePath, logPath, rawWorkstateBytes, workstate, rawWorkstateStr) = ctx;
247	
248	        // Step 1: request sha256 + candidate file hash 검증.
249	        var (_, request, evidenceExit) = VerifyApplyEvidence(envelope);
250	        if (evidenceExit.HasValue) return evidenceExit.Value;
251	
252	        // Step 2: reconciliation — 실패하면 일반 전이를 거부한다.
253	        // ★ 순서 정정(§1): reconciliation이 existing-transition보다 먼저여야 가짜 id 공격을 막는다.
254	        ReconciliationResult reconResult;
255	        try { reconResult = HandoffIntegrityChecker.Run(new ReconciliationOptions(workstatePath, logPath)); }
256	        catch (Exception ex) { WriteError($"reconciliation 실행 실패: {ex.Message}"); return 2; }
257	
258	        if (reconResult.Failures.Count > 0 || reconResult.HarnessErrors.Count > 0)
259	        {
260	            var codes = string.Join("; ", reconResult.Failures.Concat(reconResult.HarnessErrors).Select(f => f.Code));
261	            return Fail(1, envelope.TransitionId, "state-corrupted-preapply", $"reconciliation failed: {codes}");
262	        }
263	
264	        // Step 3: existing-transition 판정 (idempotent / collision / legacy-unverifiable).
265	        // ★ 순서 정정(§1): existing-transition이 pre-state hash보다 먼저여야 재시도가 산다.
266	        var existingResult = CheckExistingTransition(workstate, reconResult, envelope);
267	        if (existingResult.HasValue) return existingResult.Value;
268	
269	        // Steps 4-6: candidate 재계산 + 검증 + dry-run.
270	        var (recompCandidate, recompBytes, validateExit) =
271	            RunApplyValidatePhase(envelope, workstate, rawWorkstateStr, request!, dryRun, root);
272	        if (validateExit.HasValue) return validateExit.Value;
273	
274	        // Steps 7-10: atomic write + post-apply 검사 + v2 log.
275	        return RunApplyCommitPhase(
276	            envelope, workstatePath, logPath,
277	            rawWorkstateBytes, workstate, recompCandidate!, recompBytes!);
278	    }
279	
280	    // root를 받아 WORKSTATE를 로드한다. 실패 시 null 반환(오류는 stderr에 기록).
281	    private static (string root, string workstatePath, string logPath, byte[] rawBytes, JsonObject workstate, string rawStr)?
282	        LoadWorkstateContextFromRoot(string root)
283	    {
284	        try
285	        {
286	            var wsPath = Path.Combine(root, "docs", "handoff", "WORKSTATE.json");
287	            var lPath = Path.Combine(root, "docs", "handoff", "WORKSTATE.applier-log.jsonl");
288	            if (!File.Exists(wsPath)) { WriteError("WORKSTATE.json not found"); return null; }
289	            var bytes = File.ReadAllBytes(wsPath);
290	            var raw = Encoding.UTF8.GetString(bytes);
291	            var ws = JsonNode.Parse(raw)?.AsObject()
292	                ?? throw new InvalidOperationException("WORKSTATE.json is not a valid JSON object");
293	            return (root, wsPath, lPath, bytes, ws, raw);
294	        }
295	        catch (Exception ex) { WriteError(ex.Message); return null; }
296	    }
297	
298	    // request sha256 + candidate file hash를 검증한다. 성공 시 (rawRequest, request, null) 반환.
299	    private static (string? rawRequest, JsonObject? request, int? exitCode) VerifyApplyEvidence(EnvelopeData envelope)
300	    {
301	        if (!File.Exists(envelope.RequestPath)) { WriteError($"request file not found: {envelope.RequestPath}"); return (null, null, 2); }
302	        string rawRequest;
303	        JsonObject request;
304	        try
305	        {
306	            rawRequest = File.ReadAllText(envelope.RequestPath, new UTF8Encoding(false));
307	            var actualRequestSha = ComputeSha256(rawRequest);
308	            if (!string.Equals(actualRequestSha, envelope.RequestSha256, StringComparison.OrdinalIgnoreCase))
309	                return (null, null, Fail(1, envelope.TransitionId, "request-sha256-mismatch",
310	                    "request file changed since prepare"));
311	            request = JsonNode.Parse(rawRequest)?.AsObject()
312	                ?? throw new InvalidOperationException("request JSON must be a JSON object");
313	        }
314	        catch (Exception ex) { WriteError(ex.Message); return (null, null, 2); }
315	
316	        if (!File.Exists(envelope.CandidatePath)) { WriteError($"candidate file not found: {envelope.CandidatePath}"); return (null, null, 2); }
317	        try
318	        {
319	            var candidateFileHash = Convert.ToHexString(SHA256.HashData(File.ReadAllBytes(envelope.CandidatePath))).ToLowerInvariant();
320	            if (!string.Equals(candidateFileHash, envelope.ExpectedPostStateSha256, StringComparison.OrdinalIgnoreCase))
321	                return (null, null, Fail(1, envelope.TransitionId, "candidate-tampered",
322	                    "candidate file hash differs from envelope.expectedPostStateSha256 — evidence may have been tampered"));
323	        }
324	        catch (Exception ex) { WriteError($"candidate 파일 읽기 실패: {ex.Message}"); return (null, null, 2); }
325	
326	        return (rawRequest, request, null);
327	    }
328	
329	    // Steps 4-6: candidate 재계산 + hash 검증 + pre-state hash + request 검증 + dry-run 처리.
330	    private static (JsonObject? candidate, byte[]? bytes, int? earlyExit) RunApplyValidatePhase(
331	        EnvelopeData envelope, JsonObject workstate, string rawWorkstateStr,
332	        JsonObject request, bool dryRun, string root)
333	    {
334	        JsonObject recomputedCandidate;
335	        byte[] recomputedBytes;
336	        try
337	        {
338	            // Step 4: 메모리에서 candidate 재계산 + hash 검증 (TOCTOU 방어).
339	            recomputedCandidate = BuildCandidate(workstate, request, envelope.TransitionId, envelope.EffectiveAt);
340	            recomputedBytes = Encoding.UTF8.GetBytes(recomputedCandidate.ToJsonString(WriteOptions));
341	            var recomputedHash = Convert.ToHexString(SHA256.HashData(recomputedBytes)).ToLowerInvariant();
342	            if (!string.Equals(recomputedHash, envelope.ExpectedPostStateSha256, StringComparison.OrdinalIgnoreCase))
343	                return (null, null, Fail(1, envelope.TransitionId, "candidate-recompute-mismatch",
344	                    "recomputed candidate hash differs — WORKSTATE or request changed since prepare"));
345	        }
346	        catch (Exception ex) { WriteError($"candidate 재계산 실패: {ex.Message}"); return (null, null, 2); }
347	
348	        // Step 5: pre-state hash 검증 (미적용 ID에 한해 실행).
349	        var currentHash = ComputeSha256(rawWorkstateStr);
350	        if (!string.Equals(currentHash, envelope.ExpectedPreStateSha256, StringComparison.OrdinalIgnoreCase))
351	            return (null, null, Fail(1, envelope.TransitionId, "pre-state-hash-mismatch",
352	                $"expected={Short(envelope.ExpectedPreStateSha256)} actual={Short(currentHash)}"));
353	
354	        // Step 6: request 검증.
355	        var validErr = ValidateRequestForApply(request, envelope, workstate, root);
356	        if (validErr is not null)
357	            return (null, null, Fail(1, envelope.TransitionId, "validation-failed", validErr));
358	
359	        if (dryRun)
360	        {
361	            Console.WriteLine(new JsonObject
362	            {
363	                ["ok"] = true, ["dryRun"] = true,
364	                ["transitionId"] = envelope.TransitionId,
365	                ["previousStatus"] = workstate["status"]?.ToString(),
366	                ["newStatus"] = recomputedCandidate["status"]?.ToString(),
367	            }.ToJsonString(WriteOptions));
368	            return (null, null, 0);
369	        }
370	
371	        return (recomputedCandidate, recomputedBytes, null);
372	    }
373	
374	    // Steps 7-10: preimage 저장 → atomic write → test seam → post-apply 검사 → v2 log append.
375	    private static int RunApplyCommitPhase(
376	        EnvelopeData envelope, string workstatePath, string logPath,
377	        byte[] rawWorkstateBytes, JsonObject workstate, JsonObject recomputedCandidate, byte[] recomputedBytes)
378	    {
379	        // Step 7: preimage 저장 — atomic replace 전에 반드시 저장해야 한다.
380	        var preimage = rawWorkstateBytes;
381	        var preimageHash = Convert.ToHexString(SHA256.HashData(preimage)).ToLowerInvariant();
382	
383	        // Step 8: atomic replace — 재계산 bytes만 사용(candidate 파일은 evidence, write source 아님).
384	        try { var t = workstatePath + ".stateapplier.tmp"; File.WriteAllBytes(t, recomputedBytes); File.Move(t, workstatePath, overwrite: true); }
385	        catch (Exception ex) { WriteError($"atomic write 실패: {ex.Message}"); return 2; }
386	
387	        // 결정적 test seam — in-process 훅만 허용. 환경변수는 읽지 않는다.
388	        var seamFail = FailAfterWriteHook?.Invoke();
389	        if (seamFail is not null)
390	            return Rollback(workstatePath, logPath, preimage, preimageHash, envelope, seamFail);
391	
392	        // Step 9: 적용후 검사 — 항상 projection 실행.
393	        var projExit = RunProjection();
394	        if (projExit != 0)
395	            return Rollback(workstatePath, logPath, preimage, preimageHash, envelope, "projection-failed");
396	
397	        // 내부 checker — PendingTransitionId로 pending 면제 경로를 실증한다.
398	        ReconciliationResult reconAfter;
399	        try { reconAfter = HandoffIntegrityChecker.Run(new ReconciliationOptions(workstatePath, logPath, envelope.TransitionId)); }
400	        catch (Exception ex)
401	        {
402	            return Rollback(workstatePath, logPath, preimage, preimageHash, envelope,
403	                $"post-apply checker 실행 실패: {ex.Message}");
404	        }
405	
406	        if (reconAfter.Failures.Count > 0 || reconAfter.HarnessErrors.Count > 0)
407	        {
408	            var codes = string.Join("; ", reconAfter.Failures.Concat(reconAfter.HarnessErrors).Select(f => f.Code));
409	            return Rollback(workstatePath, logPath, preimage, preimageHash, envelope,
410	                $"post-apply-integrity-failed: {codes}");
411	        }
412	
413	        // Step 10: v2 log append — 성공 경로에서만.
414	        string newSha;
415	        try { newSha = ComputeSha256(File.ReadAllText(workstatePath, new UTF8Encoding(false))); }
416	        catch (Exception ex) { WriteError($"적용 후 hash 계산 실패: {ex.Message}"); return 2; }
417	
