447	    // rollback: preimage를 복원하고 FATAL taxonomy에 따라 exit code와 로그를 결정한다.
448	    private static int Rollback(
449	        string workstatePath, string logPath, byte[] preimage, string preimageHash,
450	        EnvelopeData envelope, string failureReason)
451	    {
452	        try
453	        {
454	            // 결정적 복원 실패 seam — 자기 시험에서 FATAL_STATE_UNKNOWN 경로를 검증한다.
455	            if (FailRestoreForTest) throw new InvalidOperationException("self-test injected restore failure");
456	            File.WriteAllBytes(workstatePath, preimage);
457	            var restoredStr = File.ReadAllText(workstatePath, new UTF8Encoding(false));
458	            var restoredHash = ComputeSha256(restoredStr);
459	
460	            if (!string.Equals(restoredHash, preimageHash, StringComparison.OrdinalIgnoreCase))
461	            {
462	                // 복원 후 hash 불일치 — FATAL.
463	                AppendLogSafe(logPath, envelope.TransitionId, "FATAL_STATE_UNKNOWN", 2);
464	                Console.Error.WriteLine(new JsonObject
465	                {
466	                    ["fatal"] = "FATAL_STATE_UNKNOWN", ["transitionId"] = envelope.TransitionId,
467	                    ["detail"] = "preimage 복원 hash 불일치 — 모든 자동작업 중단. HUMAN-INBOX 필요.",
468	                }.ToJsonString());
469	                return 2;
470	            }
471	
472	            // rollback 후 항상 projection 재생성 시도.
473	            var projExit = RunProjection();
474	            if (projExit != 0)
475	            {
476	                AppendLogSafe(logPath, envelope.TransitionId, "STATE_RESTORED_PROJECTION_NOT_VERIFIED", 2);
477	                Console.Error.WriteLine(new JsonObject
478	                {
479	                    ["fatal"] = "STATE_RESTORED_PROJECTION_NOT_VERIFIED",
480	                    ["transitionId"] = envelope.TransitionId,
481	                    ["detail"] = "WORKSTATE 복원 성공, projection 재생성 실패 — HUMAN-INBOX 필요.",
482	                }.ToJsonString());
483	                return 2;
484	            }
485	
486	            AppendLogSafe(logPath, envelope.TransitionId, "ROLLED_BACK", 1);
487	            Console.Error.WriteLine(new JsonObject
488	            {
489	                ["ok"] = false, ["result"] = "ROLLED_BACK",
490	                ["transitionId"] = envelope.TransitionId,
491	                ["failureReason"] = failureReason,
492	                ["restoredHash"] = restoredHash,
493	                ["detail"] = "WORKSTATE 복원 완료. 전이 효과 없음.",
494	            }.ToJsonString());
495	            return 1;
496	        }
497	        catch (Exception ex)
498	        {
499	            // 복원 자체 실패 — FATAL.
500	            AppendLogSafe(logPath, envelope.TransitionId, "FATAL_STATE_UNKNOWN", 2);
501	            Console.Error.WriteLine(new JsonObject
502	            {
503	                ["fatal"] = "FATAL_STATE_UNKNOWN", ["transitionId"] = envelope.TransitionId,
504	                ["detail"] = $"preimage 복원 실패: {ex.Message} — 모든 자동작업 중단.",
505	            }.ToJsonString());
506	            return 2;
507	        }
508	    }
