510	    // envelope JSON을 읽어 EnvelopeData로 파싱한다. 실패 시 null 반환.
511	    private static EnvelopeData? ReadEnvelope(string envelopePath)
512	    {
513	        if (!File.Exists(envelopePath)) { WriteError($"envelope file not found: {envelopePath}"); return null; }
514	        JsonObject env;
515	        try
516	        {
517	            env = JsonNode.Parse(File.ReadAllText(envelopePath, new UTF8Encoding(false)))?.AsObject()
518	                ?? throw new InvalidOperationException("envelope is not a JSON object");
519	        }
520	        catch (Exception ex) { WriteError($"envelope parse 실패: {ex.Message}"); return null; }
521	
522	        var kind = env["transitionKind"]?.GetValue<string>() ?? "NORMAL";
523	        var tid = env["transitionId"]?.GetValue<string>() ?? "";
524	        if (string.IsNullOrWhiteSpace(tid)) { WriteError("envelope.transitionId missing"); return null; }
525	
526	        var preHash = env["expectedPreStateSha256"]?.GetValue<string>() ?? "";
527	        var reqPath = env["requestPath"]?.GetValue<string>() ?? "";
528	        var reqSha = env["requestSha256"]?.GetValue<string>() ?? "";
529	        var effAt = env["effectiveAt"]?.GetValue<string>() ?? "";
530	        var postHash = env["expectedPostStateSha256"]?.GetValue<string>() ?? "";
531	        var candidatePath = env["candidatePath"]?.GetValue<string>() ?? "";
532	        var contractSha = env["transitionContractSha256"]?.GetValue<string>();
533	
534	        if (string.IsNullOrWhiteSpace(preHash) || string.IsNullOrWhiteSpace(reqPath) ||
535	            string.IsNullOrWhiteSpace(reqSha) || string.IsNullOrWhiteSpace(effAt) ||
536	            string.IsNullOrWhiteSpace(postHash) || string.IsNullOrWhiteSpace(candidatePath))
537	        {
538	            WriteError("envelope 필수 필드 누락 (transitionId/expectedPreStateSha256/requestPath/requestSha256/effectiveAt/expectedPostStateSha256/candidatePath)");
539	            return null;
540	        }
541	
542	        var sv = env["schemaVersion"]?.GetValue<int>() ?? 1;
543	        return new EnvelopeData(sv, kind, tid, preHash, reqPath, reqSha, effAt, postHash, contractSha, candidatePath);
544	    }
