546	    // 전이 ID가 이미 state에 있는지 판정하고 idempotent/collision/envelope-mismatch/legacy-unverifiable exit를 반환한다.
547	    private static int? CheckExistingTransition(
548	        JsonObject workstate, ReconciliationResult reconResult, EnvelopeData envelope)
549	    {
550	        var isInState = workstate["appliedTransitions"] is JsonArray applied &&
551	            applied.OfType<JsonObject>().Any(o =>
552	                string.Equals(o["id"]?.ToString(), envelope.TransitionId, StringComparison.Ordinal));
553	
554	        if (!isInState)
555	        {
556	            // 신규 전이 — self-reported contract hash가 재계산값과 일치하는지 검증 (envelope 자기신고 불신).
557	            if (!string.IsNullOrWhiteSpace(envelope.TransitionContractSha256))
558	            {
559	                var newEnvelopeHash = ComputeContractHash(
560	                    envelope.TransitionId, envelope.TransitionKind, envelope.RequestSha256,
561	                    envelope.ExpectedPreStateSha256, envelope.ExpectedPostStateSha256, envelope.EffectiveAt);
562	                if (!string.Equals(envelope.TransitionContractSha256, newEnvelopeHash, StringComparison.OrdinalIgnoreCase))
563	                    return Fail(1, envelope.TransitionId, "envelope-contract-mismatch",
564	                        "envelope.transitionContractSha256이 계산값과 다릅니다 — 위조 또는 수정됨");
565	            }
566	            return null; // 정상 경로로 진행.
567	        }
568	
569	        // state에 있음 — log 조회.
570	        reconResult.SuccessLookup.TryGetValue(envelope.TransitionId, out var logInfo);
571	        if (logInfo is null || !logInfo.Exists)
572	        {
573	            // reconciliation이 PASS했으므로 state+log 불일치는 없어야 함 — 방어 코드.
574	            return Fail(1, envelope.TransitionId, "state-corrupted-preapply",
575	                $"id '{envelope.TransitionId}' in state but not in success log");
576	        }
577	
578	        if (logInfo.SchemaVersion < 2 || string.IsNullOrWhiteSpace(logInfo.TransitionContractSha256))
579	        {
580	            // v1 log — 내용 결속 검증 불가.
581	            return Fail(1, envelope.TransitionId, "legacy-idempotency-unverifiable",
582	                $"id '{envelope.TransitionId}'는 v1 log에 있음 — contract binding 검증 불가");
583	        }
584	
585	        // v2 log — envelope 구성 필드로부터 contract hash를 재계산해 비교한다 (envelope 자기신고 불신).
586	        var computed = ComputeContractHash(
587	            envelope.TransitionId, envelope.TransitionKind, envelope.RequestSha256,
588	            envelope.ExpectedPreStateSha256, envelope.ExpectedPostStateSha256, envelope.EffectiveAt);
589	
590	        // 재계산값이 log hash와 다르면 — 다른 계약의 transition-id가 충돌함.
591	        if (!string.Equals(computed, logInfo.TransitionContractSha256, StringComparison.OrdinalIgnoreCase))
592	        {
593	            return Fail(1, envelope.TransitionId, "transition-id-collision",
594	                $"id '{envelope.TransitionId}'는 다른 contract hash로 이미 적용됨");
595	        }
596	
597	        // envelope 자기신고 hash가 계산값과 다르면 — envelope 위조 탐지.
598	        if (!string.IsNullOrWhiteSpace(envelope.TransitionContractSha256) &&
599	            !string.Equals(envelope.TransitionContractSha256, computed, StringComparison.OrdinalIgnoreCase))
600	        {
601	            return Fail(1, envelope.TransitionId, "envelope-contract-mismatch",
602	                $"envelope.transitionContractSha256이 계산값과 다릅니다 — 위조 또는 수정됨");
603	        }
604	
605	        // 동일 contract — idempotent.
606	        return ReportIdempotent(envelope.TransitionId);
607	    }
