609	    // effectiveAt을 외부에서 받아 결정적 candidate를 구성한다. UtcNow 호출 없음.
610	    private static JsonObject BuildCandidate(
611	        JsonObject current, JsonObject request, string transitionId, string effectiveAt)
612	    {
613	        var candidate = JsonNode.Parse(current.ToJsonString(WriteOptions))!.AsObject()!;
614	
615	        foreach (var key in new[] { "phaseId", "wpId", "diId", "status", "blockers", "nextActions", "updatedBy", "notes" })
616	        {
617	            if (request[key] is JsonNode node)
618	                candidate[key] = node.DeepClone();
619	        }
620	
621	        // updatedAt은 effectiveAt의 날짜 부분으로 결정한다 — UtcNow 호출 없음.
622	        if (DateTimeOffset.TryParse(effectiveAt, null, DateTimeStyles.RoundtripKind, out var ea))
623	            candidate["updatedAt"] = ea.ToString("yyyy-MM-dd");
624	
625	        if (candidate["appliedTransitions"] is not JsonArray applied)
626	        {
627	            applied = new JsonArray();
628	            candidate["appliedTransitions"] = applied;
629	        }
630	
631	        applied.Add(new JsonObject
632	        {
633	            ["id"] = transitionId,
634	            ["appliedAt"] = effectiveAt,
635	        });
636	
637	        return candidate;
638	    }
