640	    // apply 경로용 request 검증 — human-decision 플래그 없이 동작한다.
641	    private static string? ValidateRequestForApply(
642	        JsonObject request, EnvelopeData envelope, JsonObject current, string root)
643	    {
644	        if (request["phaseId"] is JsonNode ph && !Regex.IsMatch(ph.ToString(), @"^P\d{2,}$"))
645	            return $"phaseId '{ph}'는 canonical 형식(P00, P01 …)이 아닙니다";
646	        if (request["wpId"] is JsonNode wp && !Regex.IsMatch(wp.ToString(), @"^WP-\d{2,}$"))
647	            return $"wpId '{wp}'는 canonical 형식(WP-00 …)이 아닙니다";
648	        if (request["diId"] is JsonNode di && !Regex.IsMatch(di.ToString(), @"^DI-\d{2}-\d{2,}$"))
649	            return $"diId '{di}'는 canonical 형식(DI-00-05 …)이 아닙니다";
650	
651	        var newStatus = request["status"]?.ToString() ?? current["status"]?.ToString() ?? "";
652	        if (!ValidStatuses.Contains(newStatus))
653	            return $"status '{newStatus}'는 허용 목록에 없습니다";
654	
655	        var currentStatus = current["status"]?.ToString() ?? "";
656	        var currentDiId = current["diId"]?.ToString() ?? "";
657	        var requestDiId = request["diId"]?.ToString();
658	
659	        var transErr = ValidateStatusTransition(currentStatus, newStatus, currentDiId, requestDiId);
660	        if (transErr is not null) return transErr;
661	
662	        var newBlockers = request["blockers"] as JsonArray ?? current["blockers"] as JsonArray ?? new JsonArray();
663	        var newNext = request["nextActions"] as JsonArray ?? current["nextActions"] as JsonArray ?? new JsonArray();
664	
665	        if (string.Equals(newStatus, "blocked", StringComparison.OrdinalIgnoreCase) && newBlockers.Count == 0)
666	            return "status=blocked인데 blockers가 비어있습니다";
667	        if (NextActionsRequired.Contains(newStatus) && newNext.Count == 0)
668	            return $"status={newStatus}인데 nextActions가 비어있습니다";
669	
670	        if (string.Equals(newStatus, "completed", StringComparison.OrdinalIgnoreCase))
671	        {
672	            var targetDiId = requestDiId ?? currentDiId;
673	            var wsUpdatedAt = current["updatedAt"]?.ToString() ?? "";
674	            var verdictErr = ValidateVerdict(null, targetDiId, wsUpdatedAt);
675	            if (verdictErr is not null) return verdictErr;
676	        }
677	
678	        var curPhase = current["phaseId"]?.ToString();
679	        var newPhase = request["phaseId"]?.ToString();
680	        if (newPhase is not null && !string.Equals(newPhase, curPhase, StringComparison.OrdinalIgnoreCase))
681	            return $"Phase 전이({curPhase} → {newPhase})는 transitionKind=PHASE_CHANGE를 사용하세요 (이번 WP fail-closed)";
682	
683	        if (!string.IsNullOrWhiteSpace(root))
684	        {
685	            var wpId = request["wpId"]?.ToString() ?? current["wpId"]?.ToString();
686	            if (!string.IsNullOrWhiteSpace(wpId))
687	            {
688	                var regErr = ValidateWpRegistry(root, wpId);
689	                if (regErr is not null) return regErr;
690	            }
691	        }
692	        return null;
693	    }
