695	    // DI 경계와 전이 그래프를 검사한다.
696	    private static string? ValidateStatusTransition(
697	        string currentStatus, string newStatus, string currentDiId, string? requestDiId)
698	    {
699	        var isNewDi = requestDiId is not null &&
700	                      !string.Equals(requestDiId, currentDiId, StringComparison.OrdinalIgnoreCase);
701	
702	        if (isNewDi)
703	        {
704	            if (!string.Equals(currentStatus, "completed", StringComparison.OrdinalIgnoreCase))
705	                return $"새 DI 착수({currentDiId} → {requestDiId})는 현재 DI가 completed여야 합니다(현재: {currentStatus})";
706	            if (!string.Equals(newStatus, "waiting", StringComparison.OrdinalIgnoreCase) &&
707	                !string.Equals(newStatus, "in_progress", StringComparison.OrdinalIgnoreCase))
708	                return $"새 DI 착수 시 status는 waiting 또는 in_progress만 허용합니다(요청: {newStatus})";
709	            return null;
710	        }
711	
712	        if (string.Equals(currentStatus, newStatus, StringComparison.OrdinalIgnoreCase)) return null;
713	
714	        // completed는 terminal.
715	        if (string.Equals(currentStatus, "completed", StringComparison.OrdinalIgnoreCase))
716	            return $"completed 상태 전이({currentStatus} → {newStatus})는 허용되지 않습니다 — completed는 terminal 상태입니다";
717	
718	        if (AllowedTransitions.TryGetValue(currentStatus, out var allowed) && !allowed.Contains(newStatus))
719	        {
720	            var allowedStr = allowed.Count > 0 ? string.Join(", ", allowed) : "없음(terminal)";
721	            return $"status 전이 {currentStatus} → {newStatus}는 허용되지 않습니다(허용: {allowedStr})";
722	        }
723	        return null;
724	    }
