726	    // gate.json 형식·gateVerdict·failureCount·taskId 일치·stale 여부를 검증한다.
727	    private static string? ValidateVerdict(string? verdictPath, string targetDiId, string workstateUpdatedAt)
728	    {
729	        if (string.IsNullOrWhiteSpace(verdictPath))
730	            return "status=completed 전이에는 --verdict 파일이 필요합니다";
731	
732	        var normalized = verdictPath.Replace('\\', '/');
733	        var fileName = Path.GetFileName(normalized);
734	        if (!fileName.EndsWith(".gate.json", StringComparison.OrdinalIgnoreCase))
735	            return $"verdict 경로는 outputs/gates/<taskId>.gate.json 형식이어야 합니다(받음: {verdictPath})";
736	
737	        var dirPart = Path.GetDirectoryName(normalized)?.Replace('\\', '/') ?? "";
738	        if (!dirPart.EndsWith("outputs/gates", StringComparison.OrdinalIgnoreCase))
739	            return $"verdict 경로는 outputs/gates/<taskId>.gate.json 형식이어야 합니다(받음: {verdictPath})";
740	
741	        if (!File.Exists(verdictPath)) return $"verdict file not found: {verdictPath}";
742	
743	        var gateJson = JsonNode.Parse(File.ReadAllText(verdictPath))?.AsObject();
744	        if (gateJson is null) return "gate JSON이 유효하지 않습니다";
745	
746	        var gateVerdict = gateJson["gateVerdict"]?.ToString();
747	        if (!string.Equals(gateVerdict, "PASS", StringComparison.OrdinalIgnoreCase))
748	            return $"gate verdict가 PASS가 아닙니다(gateVerdict={gateVerdict ?? "null"})";
749	
750	        var failureCount = gateJson["failureCount"]?.GetValue<int>() ?? -1;
751	        if (failureCount != 0) return $"gate failureCount가 0이 아닙니다(failureCount={failureCount})";
752	
753	        var gateTaskId = gateJson["taskId"]?.ToString();
754	        if (!string.Equals(gateTaskId, targetDiId, StringComparison.OrdinalIgnoreCase))
755	            return $"gate taskId({gateTaskId ?? "null"})가 전이 대상 DI({targetDiId})와 일치하지 않습니다";
756	
757	        var createdAtStr = gateJson["createdAt"]?.ToString();
758	        if (createdAtStr is not null &&
759	            DateTimeOffset.TryParse(createdAtStr, out var createdAt) &&
760	            DateTime.TryParse(workstateUpdatedAt, out var wsUpdated) &&
761	            createdAt.Date < wsUpdated.Date)
762	        {
763	            return $"gate 증거가 WORKSTATE updatedAt({workstateUpdatedAt})보다 오래됐습니다(gate createdAt={createdAt:yyyy-MM-dd})";
764	        }
765	        return null;
766	    }
