768	    // wpId가 WP-REGISTRY.json에 등록되어 있는지 검사한다.
769	    private static string? ValidateWpRegistry(string root, string wpId)
770	    {
771	        var registryPath = Path.Combine(root, "docs", "handoff", "WP-REGISTRY.json");
772	        if (!File.Exists(registryPath)) return "WP-REGISTRY.json not found — WP 등록표가 없습니다";
