782	    // 고정 순서 JSON 직렬화로 계약 hash를 계산한다.
783	    private static string ComputeContractHash(
784	        string transitionId, string transitionKind, string requestSha256,
785	        string preStateSha256, string postStateSha256, string effectiveAt)
786	    {
787	        var sb = new StringBuilder();
788	        sb.Append("{\"effectiveAt\":\"").Append(effectiveAt).Append('"');
789	        sb.Append(",\"postStateSha256\":\"").Append(postStateSha256).Append('"');
790	        sb.Append(",\"preStateSha256\":\"").Append(preStateSha256).Append('"');
791	        sb.Append(",\"requestSha256\":\"").Append(requestSha256).Append('"');
792	        sb.Append(",\"transitionId\":\"").Append(transitionId).Append('"');
793	        sb.Append(",\"transitionKind\":\"").Append(transitionKind).Append("\"}");
794	        return ComputeSha256(sb.ToString());
795	    }
