843	        {
844	            ["ok"] = true,
845	            ["transitionId"] = transitionId,
846	            ["idempotent"] = true,
847	            ["note"] = "이 transition-id는 이미 적용됐다 — 상태를 바꾸지 않는다",
848	        }.ToJsonString(WriteOptions));
849	        return 0;
850	    }
851	
852	    // prepare 인수를 파싱한다.
853	    private static PrepareOptions? ParsePrepareArgs(string[] args)
854	    {
855	        var map = ParseFlagMap(args, 2);
856	        var dryRun = map.ContainsKey("dry-run-flag"); map.Remove("dry-run-flag");
857	        if (!map.TryGetValue("transition-id", out var tid) || string.IsNullOrWhiteSpace(tid)) return null;
858	        if (!map.TryGetValue("request", out var req) || string.IsNullOrWhiteSpace(req)) return null;
859	        return new PrepareOptions(tid, req, dryRun);
860	    }
861	
862	    // apply 인수를 파싱한다.
863	    private static ApplyOptions? ParseApplyArgs(string[] args)
864	    {
865	        var map = ParseFlagMap(args, 2);
866	        var dryRun = map.ContainsKey("dry-run-flag"); map.Remove("dry-run-flag");
867	        if (!map.TryGetValue("envelope", out var env) || string.IsNullOrWhiteSpace(env)) return null;
868	        map.TryGetValue("verdict", out var verdict);
869	        return new ApplyOptions(env, verdict, dryRun);
870	    }
871	
872	    // args[startIndex]부터 --key value 쌍을 파싱한다. --dry-run은 "dry-run-flag"="1"로 저장.
873	    private static Dictionary<string, string> ParseFlagMap(string[] args, int startIndex)
874	    {
875	        var map = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
876	        for (var i = startIndex; i < args.Length; i++)
877	        {
878	            if (string.Equals(args[i], "--dry-run", StringComparison.OrdinalIgnoreCase))
879	            {
880	                map["dry-run-flag"] = "1";
881	                continue;
882	            }
883	            if (args[i].StartsWith("--", StringComparison.Ordinal) && i + 1 < args.Length)
884	            {
885	                map[args[i][2..]] = args[i + 1];
886	                i++;
887	            }
888	        }
889	        return map;
890	    }
891	
892	    // 알 수 없거나 삭제된 옵션을 검사해 오류 메시지를 반환한다. 없으면 null.
893	    private static string? ValidateOptions(Dictionary<string, string> map, HashSet<string> knownKeys)
894	    {
895	        foreach (var key in map.Keys)
896	        {
897	            if (knownKeys.Contains(key)) continue;
898	            if (RemovedOptions.TryGetValue(key, out var msg)) return msg;
899	            return $"unknown-option: --{key}";
900	        }
901	        return null;
902	    }
