904	    // ProjectionOverride가 있으면 그것을, 없으면 ProjectionCli를 실행한다.
905	    private static int RunProjection()
906	        => ProjectionOverride is not null ? ProjectionOverride() : ProjectionCli.Run(["projection"]);
