908	    // 문자열의 SHA-256을 소문자 hex로 반환한다.
909	    private static string ComputeSha256(string content)
910	        => Convert.ToHexString(SHA256.HashData(Encoding.UTF8.GetBytes(content))).ToLowerInvariant();
911	
912	    // stderr에 JSON 오류 메시지를 출력한다.
913	    private static void WriteError(string message)
914	        => Console.Error.WriteLine($"{{\"error\":\"{message}\"}}");
915	
916	    // 실패 결과를 stderr에 출력하고 지정 exit code를 반환한다.
917	    private static int Fail(int exitCode, string transitionId, string reason, string detail)
918	    {
919	        Console.Error.WriteLine(new JsonObject
920	        {
921	            ["ok"] = false,
922	            ["transitionId"] = transitionId,
923	            ["reason"] = reason,
924	            ["detail"] = detail,
925	        }.ToJsonString());
