929	    // sha256 문자열의 앞 16자 + "..."를 반환한다.
930	    private static string Short(string s) => s.Length > 16 ? s[..16] + "..." : s;
931	
932	    // state-transition --self-test: rollback·정상·FATAL 경로를 in-process로 단언한다.
933	    private static int RunSelfTest()
934	    {
935	        var tmpBase = Path.Combine(Path.GetTempPath(), $"st-selftest-{Guid.NewGuid():N}");
936	        try { return RunSelfTestInDir(tmpBase); }
937	        finally
938	        {
939	            try { if (Directory.Exists(tmpBase)) Directory.Delete(tmpBase, recursive: true); } catch { }
940	        }
941	    }
