943	    // 임시 저장소를 만들고 4개 case를 순서대로 실행한다.
944	    private static int RunSelfTestInDir(string tmpRoot)
945	    {
946	        var wsDir = Path.Combine(tmpRoot, "docs", "handoff");
947	        var outDir = Path.Combine(tmpRoot, "outputs", "state-transition");
948	        Directory.CreateDirectory(wsDir);
949	        Directory.CreateDirectory(outDir);
950	        Directory.CreateDirectory(Path.Combine(tmpRoot, ".git")); // GitTools.FindRepoRoot 기준점
951	        var wsPath = Path.Combine(wsDir, "WORKSTATE.json");
952	        var logPath = Path.Combine(wsDir, "WORKSTATE.applier-log.jsonl");
953	        var reqPath = Path.Combine(tmpRoot, "req.json");
954	        var wsContent = "{\"schemaVersion\":1,\"diId\":\"DI-00-04\",\"status\":\"in_progress\","
955	            + "\"blockers\":[],\"nextActions\":[\"test\"],\"phaseId\":\"P00\",\"wpId\":\"WP-00\","
956	            + "\"updatedAt\":\"2026-07-14\",\"updatedBy\":\"self-test\",\"appliedTransitions\":[]}";
957	        File.WriteAllText(wsPath, wsContent, new UTF8Encoding(false));
958	        File.WriteAllText(logPath, "", new UTF8Encoding(false));
959	        File.WriteAllText(Path.Combine(wsDir, "WP-REGISTRY.json"),
960	            "{\"wps\":[{\"wpId\":\"WP-00\",\"title\":\"Self Test\"}]}", new UTF8Encoding(false));
961	        File.WriteAllText(reqPath,
962	            "{\"status\":\"in_progress\",\"nextActions\":[\"test\"],\"phaseId\":\"P00\","
963	            + "\"wpId\":\"WP-00\",\"diId\":\"DI-00-04\",\"updatedBy\":\"self-test\"}",
964	            new UTF8Encoding(false));
965	        var mismatches = new JsonArray();
966	        var caseResults = new JsonArray();
967	        RunCaseNormalApply(tmpRoot, reqPath, wsPath, wsContent, logPath, outDir, caseResults, mismatches);
968	        RunCaseRollbackAfterWrite(tmpRoot, reqPath, wsPath, wsContent, logPath, outDir, caseResults, mismatches);
969	        RunCaseRollbackRestoresLog(logPath, caseResults, mismatches);
970	        RunCaseFatalRestoreFailed(tmpRoot, reqPath, wsPath, wsContent, logPath, outDir, caseResults, mismatches);
971	        ProjectionOverride = null;
972	        if (mismatches.Count == 0)
973	        {
974	            Console.WriteLine(new JsonObject { ["selfTest"] = "state-transition", ["verdict"] = "PASS",
975	                ["casesRun"] = caseResults.Count, ["cases"] = caseResults }.ToJsonString(WriteOptions));
976	            return 0;
977	        }
978	        Console.Error.WriteLine(new JsonObject { ["selfTest"] = "state-transition", ["verdict"] = "FAIL",
979	            ["mismatchCount"] = mismatches.Count, ["mismatches"] = mismatches,
980	            ["cases"] = caseResults }.ToJsonString(WriteOptions));
981	        return 1;
982	    }
