984	    // case: normal-apply — 주입 없음, exit 0, v2 log 기록, WS 변경.
985	    private static void RunCaseNormalApply(string tmpRoot, string reqPath, string wsPath, string wsContent,
986	        string logPath, string outDir, JsonArray caseResults, JsonArray mismatches)
987	    {
988	        RestoreFixture(wsPath, wsContent, logPath);
989	        ProjectionOverride = () => 0; FailAfterWriteHook = null; FailRestoreForTest = false;
990	        var prepExit = RunPrepareCore(tmpRoot, new PrepareOptions("ST-NORMAL", reqPath, false));
991	        var preimageHash = ComputeSha256(File.ReadAllText(wsPath, new UTF8Encoding(false)));
992	        var env = ReadEnvelope(Path.Combine(outDir, "ST-NORMAL.envelope.json"));
993	        int? applyExit = null;
994	        if (env is not null && prepExit == 0)
995	        {
996	            var ctx = LoadWorkstateContextFromRoot(tmpRoot);
997	            if (ctx is not null) applyExit = ApplyEnvelopeCore(ctx.Value, env, false);
998	        }
999	        var logLines = File.Exists(logPath) ? File.ReadAllLines(logPath) : [];
1000	        var okLogged = logLines.Any(l => l.Contains("\"ok\"") && l.Contains("ST-NORMAL"));
1001	        var wsMoved = !string.Equals(ComputeSha256(File.ReadAllText(wsPath, new UTF8Encoding(false))), preimageHash);
1002	        var ok = applyExit == 0 && okLogged && wsMoved;
1003	        caseResults.Add(new JsonObject { ["case"] = "normal-apply", ["exit"] = applyExit, ["v2LogWritten"] = okLogged, ["wsChanged"] = wsMoved, ["pass"] = ok });
1004	        if (!ok) mismatches.Add(new JsonObject { ["case"] = "normal-apply", ["expected"] = "exit=0, v2-log-ok, ws-changed", ["actual"] = $"exit={applyExit},log={okLogged},ws={wsMoved}" });
1005	    }
1006	
1007	    // case: rollback-after-write — 쓰기 직후 실패 주입, exit 1 ROLLED_BACK, hash==preimage, v2 ok 미기록.
1008	    private static void RunCaseRollbackAfterWrite(string tmpRoot, string reqPath, string wsPath, string wsContent,
1009	        string logPath, string outDir, JsonArray caseResults, JsonArray mismatches)
1010	    {
1011	        RestoreFixture(wsPath, wsContent, logPath);
1012	        ProjectionOverride = () => 0; FailAfterWriteHook = () => "self-test-failure"; FailRestoreForTest = false;
1013	        var prepExit = RunPrepareCore(tmpRoot, new PrepareOptions("ST-ROLLBACK", reqPath, false));
1014	        var preimageHash = Convert.ToHexString(SHA256.HashData(File.ReadAllBytes(wsPath))).ToLowerInvariant();
1015	        var env = ReadEnvelope(Path.Combine(outDir, "ST-ROLLBACK.envelope.json"));
1016	        int? applyExit = null;
1017	        if (env is not null && prepExit == 0)
1018	        {
1019	            var ctx = LoadWorkstateContextFromRoot(tmpRoot);
1020	            if (ctx is not null) applyExit = ApplyEnvelopeCore(ctx.Value, env, false);
1021	        }
1022	        FailAfterWriteHook = null;
1023	        var restoredHash = ComputeSha256(File.ReadAllText(wsPath, new UTF8Encoding(false)));
1024	        var logLines = File.Exists(logPath) ? File.ReadAllLines(logPath) : [];
1025	        var rolledBack = logLines.Any(l => l.Contains("ROLLED_BACK") && l.Contains("ST-ROLLBACK"));
1026	        var noOkLog = !logLines.Any(l => l.Contains("\"ok\"") && l.Contains("ST-ROLLBACK"));
1027	        var hashRestored = string.Equals(restoredHash, preimageHash, StringComparison.OrdinalIgnoreCase);
1028	        var ok = applyExit == 1 && rolledBack && noOkLog && hashRestored;
1029	        caseResults.Add(new JsonObject { ["case"] = "rollback-after-write", ["exit"] = applyExit, ["rolledBack"] = rolledBack, ["noOkLog"] = noOkLog, ["hashRestored"] = hashRestored, ["pass"] = ok });
1030	        if (!ok) mismatches.Add(new JsonObject { ["case"] = "rollback-after-write", ["expected"] = "exit=1,ROLLED_BACK,no-ok-log,hash==preimage", ["actual"] = $"exit={applyExit},rolledBack={rolledBack},noOkLog={noOkLog},hashRestored={hashRestored}" });
1031	    }
1032	
1033	    // case: rollback-restores-log — rollback 후 v2 ok 항목이 없음을 재확인한다.
1034	    private static void RunCaseRollbackRestoresLog(string logPath, JsonArray caseResults, JsonArray mismatches)
1035	    {
1036	        var logLines = File.Exists(logPath) ? File.ReadAllLines(logPath) : [];
1037	        var noV2OkEntry = !logLines.Any(l => l.Contains("\"result\":\"ok\"") && l.Contains("ST-ROLLBACK"));
1038	        caseResults.Add(new JsonObject { ["case"] = "rollback-restores-log", ["noV2OkEntry"] = noV2OkEntry, ["pass"] = noV2OkEntry });
1039	        if (!noV2OkEntry) mismatches.Add(new JsonObject { ["case"] = "rollback-restores-log", ["expected"] = "v2-ok-log-not-written", ["actual"] = "v2-ok-log-was-written" });
1040	    }
1041	
1042	    // case: fatal-restore-failed — 복원 자체를 실패시켜 exit 2 FATAL_STATE_UNKNOWN을 검증한다.
1043	    private static void RunCaseFatalRestoreFailed(string tmpRoot, string reqPath, string wsPath, string wsContent,
1044	        string logPath, string outDir, JsonArray caseResults, JsonArray mismatches)
1045	    {
1046	        RestoreFixture(wsPath, wsContent, logPath);
1047	        ProjectionOverride = () => 0; FailAfterWriteHook = () => "self-test-fatal"; FailRestoreForTest = true;
1048	        var prepExit = RunPrepareCore(tmpRoot, new PrepareOptions("ST-FATAL", reqPath, false));
1049	        var env = ReadEnvelope(Path.Combine(outDir, "ST-FATAL.envelope.json"));
1050	        int? applyExit = null;
1051	        if (env is not null && prepExit == 0)
1052	        {
1053	            var ctx = LoadWorkstateContextFromRoot(tmpRoot);
1054	            if (ctx is not null) applyExit = ApplyEnvelopeCore(ctx.Value, env, false);
1055	        }
1056	        FailAfterWriteHook = null; FailRestoreForTest = false;
1057	        var logLines = File.Exists(logPath) ? File.ReadAllLines(logPath) : [];
1058	        var fatalLogged = logLines.Any(l => l.Contains("FATAL_STATE_UNKNOWN") && l.Contains("ST-FATAL"));
1059	        var ok = applyExit == 2 && fatalLogged;
1060	        caseResults.Add(new JsonObject { ["case"] = "fatal-restore-failed", ["exit"] = applyExit, ["fatalLogged"] = fatalLogged, ["pass"] = ok });
1061	        if (!ok) mismatches.Add(new JsonObject { ["case"] = "fatal-restore-failed", ["expected"] = "exit=2,FATAL_STATE_UNKNOWN", ["actual"] = $"exit={applyExit},fatal={fatalLogged}" });
1062	    }
1063	
1064	    // 자기 시험용 fixture 초기화 — WORKSTATE를 preimage로 되돌리고 log를 비운다.
1065	    private static void RestoreFixture(string wsPath, string wsContent, string logPath)
1066	    {
