        var escalated = EscalateRefeedback(ref tier1, ref runLog, state);
        var result = new JsonObject
        {
            ["escalated"] = escalated,
            ["verdict"] = tier1.Verdict,
            ["reasonCode"] = tier1.ReasonCode,
            ["reportVerdict"] = report["verdict"]?.GetValue<string>() ?? "",
