29	
30	    // 자기 시험 seam — in-process 훅만. production 진입점에서 설정 불가.
31	    internal static bool NonInteractiveOverride;
32	    internal static PreconOverride? TestPrecon;
33	
34	    // trust-origin 진입점.
35	    internal static int Run(string[] args)
36	    {
37	        var sub = args.Length > 1 ? args[1] : "";
