45	    }
46	
47	    // declare: 비대화형 거부(약한 안전장치), ack 확인, precondition 검사, record 생성.
48	    private static int RunDeclare(string[] args)
49	    {
50	        // 약한 안전장치(신원 증명 아님) — 비대화형 실행 기본 거부.
51	        // 프로그램은 사람과 AI를 구분 못 한다(HUMAN_DECLARED_NOT_CRYPTOGRAPHICALLY_VERIFIED).
52	        if (!NonInteractiveOverride && (Console.IsInputRedirected || !Environment.UserInteractive))
53	        {
54	            Console.Error.WriteLine(
55	                "{\"error\":\"비대화형 실행 기본 거부\",\"code\":\"non-interactive-rejected\","
56	                + "\"note\":\"HUMAN_DECLARED_NOT_CRYPTOGRAPHICALLY_VERIFIED — 프로그램은 사람과 AI를 구분하지 못합니다\"}");
57	            return 1;
58	        }
