83	            Path.Combine(root, RecordRelPath.Replace('/', Path.DirectorySeparatorChar)));
84	        var wsPath = Path.Combine(root, "docs", "handoff", "WORKSTATE.json");
85	        var logPath = Path.Combine(root, "docs", "handoff", "WORKSTATE.applier-log.jsonl");
86	        var precon = TestPrecon;
87	
88	        // 기존 epoch 확인: trustEpoch >= 1 이면 거부.
89	        var epochExit = CheckEpochGuard(recordPath);
90	        if (epochExit.HasValue) return epochExit.Value;
91	
92	        // WORKSTATE 읽기.
93	        if (!File.Exists(wsPath)) { WriteError("WORKSTATE.json not found"); return 2; }
94	        string wsContent;
95	        try { wsContent = File.ReadAllText(wsPath, new UTF8Encoding(false)); }
96	        catch (Exception ex) { WriteError($"WORKSTATE.json 읽기 실패: {ex.Message}"); return 2; }
97	
98	        // 선행조건 2: reconciliation 실행 + 부분집합 검사.
99	        var (reconResult, reconExit) = RunReconciliationCheck(wsPath, logPath, knownExceptions);
100	        if (reconExit.HasValue) return reconExit.Value;
101	
102	        // 선행조건 1·3·4·9·10 검사.
103	        var preconExit = CheckAllPreconditions(root, precon);
104	        if (preconExit.HasValue) return preconExit.Value;
105	
106	        // 선행조건 5: WORKSTATE hash / 선행조건 6: applier-log hash.
107	        var workstateSha256 = ComputeSha256(wsContent);
108	        var logContent = File.Exists(logPath) ? File.ReadAllText(logPath, new UTF8Encoding(false)) : "";
109	        var applierLogSha256 = ComputeSha256(logContent);
110	
111	        // 선행조건 7: baseline commit hash.
112	        var (baselineCommit, commitExit) = GetBaselineCommit(root, precon);
113	        if (commitExit.HasValue) return commitExit.Value;
114	
115	        // record 생성 — declarationCommit 없음(자기참조 방지). 이 경로 외에는 쓰지 않는다.
116	        return BuildAndWriteRecord(
117	            recordPath, baselineCommit!, workstateSha256, applierLogSha256, reconResult!, knownExceptions);
118	    }
