120	    // 기존 epoch 확인 — trustEpoch >= 1 이면 exit 1, 없으면 null.
121	    private static int? CheckEpochGuard(string recordPath)
122	    {
123	        if (!File.Exists(recordPath)) return null;
124	        try
125	        {
126	            var existing = JsonNode.Parse(File.ReadAllText(recordPath))?.AsObject();
127	            if ((existing?["trustEpoch"]?.GetValue<int>() ?? 0) >= 1)
128	            {
129	                WriteError("trustEpoch >= 1 이미 존재 — 재선언 거부. 새 trust origin은 VERIFIED_HUMAN_APPROVAL receipt 필요");
130	                return 1;
131	            }
132	        }
133	        catch { /* 파싱 불가 시 아래 CreateNew에서 처리 */ }
134	        return null;
135	    }
