137	    // reconciliation을 실행하고 failure ⊆ knownExceptions 부분집합 검사를 수행한다.
138	    private static (ReconciliationResult? result, int? exitCode) RunReconciliationCheck(
139	        string wsPath, string logPath, List<KnownException> knownExceptions)
140	    {
141	        ReconciliationResult reconResult;
142	        try { reconResult = HandoffIntegrityChecker.Run(new ReconciliationOptions(wsPath, logPath)); }
143	        catch (Exception ex) { WriteError($"reconciliation 실행 실패: {ex.Message}"); return (null, 2); }
144	
145	        // 하네스 오류 시 별도 중단 — subject가 없어 부분집합 검사를 우회할 수 있다.
146	        if (reconResult.HarnessErrors.Count > 0)
147	        {
148	            var errs = string.Join("; ", reconResult.HarnessErrors.Select(e => e.Code));
149	            WriteError($"reconciliation 하네스 오류 — 선행조건 2 검증 불가: {errs}");
150	            return (null, 2);
151	        }
152	
153	        // 부분집합 검사: failures ⊆ knownExceptions. 명시되지 않은 failure → 선언 거부.
154	        var failureSubjects = reconResult.Failures
155	            .Select(f => f.Subject).Where(s => !string.IsNullOrWhiteSpace(s))
156	            .ToHashSet(StringComparer.OrdinalIgnoreCase);
157	        var knownSubjects = knownExceptions.Select(e => e.Subject).ToHashSet(StringComparer.OrdinalIgnoreCase);
158	        var unlisted = failureSubjects.Except(knownSubjects).ToList();
159	        if (unlisted.Count > 0)
160	        {
161	            Console.Error.WriteLine(new JsonObject
162	            {
163	                ["error"] = "명시되지 않은 reconciliation failure — 선언 거부",
164	                ["code"] = "unlisted-reconciliation-failure",
165	                ["unlistedSubjects"] = new JsonArray(unlisted.Select(s => (JsonNode?)s).ToArray()),
166	            }.ToJsonString());
167	            return (null, 1);
168	        }
169	        return (reconResult, null);
170	    }
