172	    // 선행조건 1·3·4·9·10을 검사한다. 미충족 시 exit code 반환, 전부 충족 시 null.
173	    private static int? CheckAllPreconditions(string root, PreconOverride? precon)
174	    {
175	        if (precon is not null && !precon.BuildVerified)
176	            { WriteError("선행조건 1 미충족 — build exit 0 필요"); return 1; }
177	        var filesTracked = precon?.FilesTracked ?? CheckFilesTracked(root);
178	        if (!filesTracked)
179	            { WriteError("선행조건 3 미충족 — StateApplierCli.cs 또는 HandoffIntegrityChecker.cs가 git-tracked 상태가 아님"); return 1; }
180	        var noDirectMod = precon?.NoDirectMod ?? CheckNoDirectMod(root);
181	        if (!noDirectMod)
182	            { WriteError("선행조건 4 미충족 — WORKSTATE.json 또는 applier-log.jsonl가 working tree에서 직접 수정됨"); return 1; }
183	        var autoOff = precon?.AutoLauncherOff ?? true;
184	        if (!autoOff)
185	            { WriteError("선행조건 9 미충족 — 자동 launcher 비활성 확인 필요"); return 1; }
186	        var highRiskClosed = precon?.HighRiskClosed ?? true;
187	        if (!highRiskClosed)
188	            { WriteError("선행조건 10 미충족 — high-risk transition fail-closed 확인 필요"); return 1; }
189	        return null;
190	    }
