390	    // case: record-path-fixed — 선언은 canonical record 경로 외 다른 파일을 쓰지 않는다.
391	    private static void RunCaseRecordPathFixed(
392	        string tmpRoot, string wsPath, string logPath, string recordPath,
393	        string wsClean, PreconOverride precon, JsonArray caseResults, JsonArray mismatches)
394	    {
395	        ResetFixture(wsPath, wsClean, logPath, recordPath);
396	        NonInteractiveOverride = true; TestPrecon = precon;
397	        var beforeFiles = Directory.GetFiles(tmpRoot, "*", SearchOption.AllDirectories)
398	            .Select(Path.GetFullPath).ToHashSet(StringComparer.OrdinalIgnoreCase);
399	        var exit = RunDeclareCore(tmpRoot, []);
400	        var afterFiles = Directory.GetFiles(tmpRoot, "*", SearchOption.AllDirectories)
401	            .Select(Path.GetFullPath).ToHashSet(StringComparer.OrdinalIgnoreCase);
402	        var newFiles = afterFiles.Except(beforeFiles).ToList();
403	        var canonicalPath = Path.GetFullPath(recordPath);
404	        var onlyCanonical = exit == 0 && newFiles.Count == 1 &&
405	            string.Equals(newFiles[0], canonicalPath, StringComparison.OrdinalIgnoreCase);
406	        caseResults.Add(new JsonObject { ["case"] = "record-path-fixed", ["exit"] = exit,
407	            ["newFileCount"] = newFiles.Count, ["onlyCanonicalPath"] = onlyCanonical, ["pass"] = onlyCanonical });
408	        if (!onlyCanonical) mismatches.Add(new JsonObject { ["case"] = "record-path-fixed",
409	            ["expected"] = "exit=0, 신규 파일 1개만 (canonical path)",
410	            ["actual"] = $"exit={exit},newFiles=[{string.Join(";", newFiles)}]" });
411	    }
