421	    // knownExceptions JSON 배열을 파싱한다.
422	    private static List<KnownException> ParseKnownExceptions(JsonNode? node)
423	    {
424	        var list = new List<KnownException>();
425	        if (node is not JsonArray arr) return list;
426	        foreach (var item in arr.OfType<JsonObject>())
427	        {
428	            var subject = item["subject"]?.GetValue<string>() ?? "";
429	            if (string.IsNullOrWhiteSpace(subject)) continue;
430	            list.Add(new KnownException(
431	                Code: item["code"]?.GetValue<string>() ?? "", Subject: subject,
432	                What: item["what"]?.GetValue<string>() ?? "", Why: item["why"]?.GetValue<string>() ?? "",
433	                WhyNotReplayed: item["whyNotReplayed"]?.GetValue<string>() ?? ""));
434	        }
435	        return list;
436	    }
