443	            arr.Add(new JsonObject { ["code"] = e.Code, ["subject"] = e.Subject, ["what"] = e.What,
444	                ["why"] = e.Why, ["whyNotReplayed"] = e.WhyNotReplayed });
445	        return arr;
446	    }
