456	    // WORKSTATE·applier-log가 working tree에서 직접 수정되지 않았는지 확인한다.
457	    private static bool CheckNoDirectMod(string root)
458	    {
459	        var output = RunGitOutput(root,
460	            "status --porcelain -- docs/handoff/WORKSTATE.json docs/handoff/WORKSTATE.applier-log.jsonl");
461	        return string.IsNullOrWhiteSpace(output);
462	    }
463	
464	    // git 명령의 exit code를 반환한다.
465	    private static int RunGitExitCode(string root, string arguments)
466	    {
467	        using var p = new Process();
468	        p.StartInfo = new ProcessStartInfo("git", arguments)
469	        {
470	            WorkingDirectory = root, RedirectStandardOutput = true,
471	            RedirectStandardError = true, UseShellExecute = false,
472	        };
473	        p.Start(); p.StandardOutput.ReadToEnd(); p.StandardError.ReadToEnd(); p.WaitForExit();
474	        return p.ExitCode;
475	    }
476	
477	    // git 명령의 stdout을 반환한다.
478	    private static string RunGitOutput(string root, string arguments)
479	    {
480	        using var p = new Process();
481	        p.StartInfo = new ProcessStartInfo("git", arguments)
482	        {
483	            WorkingDirectory = root, RedirectStandardOutput = true,
484	            RedirectStandardError = true, UseShellExecute = false,
485	        };
486	        p.Start(); var output = p.StandardOutput.ReadToEnd(); p.WaitForExit();
487	        return output;
488	    }
489	
490	    // --key value 쌍을 파싱한다.
491	    private static Dictionary<string, string> ParseFlagMap(string[] args, int startIndex)
492	    {
493	        var map = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
494	        for (var i = startIndex; i < args.Length; i++)
495	            if (args[i].StartsWith("--", StringComparison.Ordinal) && i + 1 < args.Length)
496	            { map[args[i][2..]] = args[i + 1]; i++; }
497	        return map;
498	    }
499	
500	    // SHA-256을 소문자 hex로 계산한다.
501	    private static string ComputeSha256(string content)
502	        => Convert.ToHexString(SHA256.HashData(Encoding.UTF8.GetBytes(content))).ToLowerInvariant();
503	
504	    // stderr에 JSON 오류 메시지를 출력한다.
505	    private static void WriteError(string message)
506	        => Console.Error.WriteLine($"{{\"error\":\"{message}\"}}");
507	}
